import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"搜索索引的数据库同步、更新、删除与重建","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"search-sync-update-delete"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/14-search-sync-update-delete.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/14-search-sync-update-delete.md","lastUpdated":null}'),l={name:"05-backend-data/notes/07-cache-messaging-storage/14-search-sync-update-delete.md"};function o(s,e,n,d,h,p){return t(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="搜索索引的数据库同步、更新、删除与重建" tabindex="-1">搜索索引的数据库同步、更新、删除与重建 <a class="header-anchor" href="#搜索索引的数据库同步、更新、删除与重建" aria-label="Permalink to &quot;搜索索引的数据库同步、更新、删除与重建&quot;">​</a></h1><p>搜索索引是数据库事实的异步投影。同步设计必须处理事务提交、重复、乱序、删除 tombstone、CDC 水位、全量快照与增量衔接，并能从事实源重建。</p><h2 id="_1-能力边界与机制图" tabindex="-1">1. 能力边界与机制图 <a class="header-anchor" href="#_1-能力边界与机制图" aria-label="Permalink to &quot;1. 能力边界与机制图&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;事实输入&quot;] --&gt; B[&quot;索引/处理机制&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;查询或派生输出&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;验证与观测&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;失败恢复/重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>同步链路的事实身份是数据库主键、提交版本和变更位置。每个索引写入必须能关联 outbox/CDC event，旧版本和重复事件不得覆盖新文档，删除必须以 tombstone 或等价事实传播。</p><h2 id="_2-dual-write" tabindex="-1">2. Dual write <a class="header-anchor" href="#_2-dual-write" aria-label="Permalink to &quot;2. Dual write&quot;">​</a></h2><p>机制：应用同时写DB和搜索存在不可原子的失败窗口。</p><p>实际使用：仅作低风险优化且有对账。</p><p>主要失败：把两次成功响应当事务。</p><p>验证方法：在每个崩溃点测试。</p><p>取舍：代码少但会漏/幽灵文档。</p><p>生产实现 Dual write 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_3-outbox" tabindex="-1">3. Outbox <a class="header-anchor" href="#_3-outbox" aria-label="Permalink to &quot;3. Outbox&quot;">​</a></h2><p>机制：业务事务内写领域事件。</p><p>实际使用：可靠传递变更意图。</p><p>主要失败：publisher先标记再发送。</p><p>验证方法：监控oldest unpublished。</p><p>取舍：增加表和publisher运维。</p><p>生产实现 Outbox 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_4-cdc" tabindex="-1">4. CDC <a class="header-anchor" href="#_4-cdc" aria-label="Permalink to &quot;4. CDC&quot;">​</a></h2><p>机制：从WAL/binlog捕获提交变化。</p><p>实际使用：覆盖所有数据库写者。</p><p>主要失败：忽略复制槽积压和schema演进。</p><p>验证方法：观察LSN/slot lag。</p><p>取舍：低延迟但耦合变更日志。</p><p>生产实现 CDC 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_5-external-version" tabindex="-1">5. External version <a class="header-anchor" href="#_5-external-version" aria-label="Permalink to &quot;5. External version&quot;">​</a></h2><p>机制：文档保存源aggregate version。</p><p>实际使用：拒绝旧事件覆盖新状态。</p><p>主要失败：使用墙钟排序并发事件。</p><p>验证方法：乱序回放验证最高版本。</p><p>取舍：需要事实源分配单调版本。</p><p>生产实现 External version 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_6-tombstone" tabindex="-1">6. Tombstone <a class="header-anchor" href="#_6-tombstone" aria-label="Permalink to &quot;6. Tombstone&quot;">​</a></h2><p>机制：删除事件携带删除version。</p><p>实际使用：防旧upsert复活。</p><p>主要失败：物理删除后不保留水位。</p><p>验证方法：发送旧事件验证不复活。</p><p>取舍：保留状态有存储成本。</p><p>生产实现 Tombstone 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_7-bulk-api" tabindex="-1">7. Bulk API <a class="header-anchor" href="#_7-bulk-api" aria-label="Permalink to &quot;7. Bulk API&quot;">​</a></h2><p>机制：批量索引提升吞吐。</p><p>实际使用：回填和追赶。</p><p>主要失败：只看HTTP 200忽略逐项错误。</p><p>验证方法：解析每项status并分类重试。</p><p>取舍：吞吐高但失败隔离复杂。</p><p>生产实现 Bulk API 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_8-refresh" tabindex="-1">8. Refresh <a class="header-anchor" href="#_8-refresh" aria-label="Permalink to &quot;8. Refresh&quot;">​</a></h2><p>机制：提交后near-real-time可见。</p><p>实际使用：控制读可见延迟。</p><p>主要失败：每条写refresh=true压垮集群。</p><p>验证方法：测refresh/segment/merge。</p><p>取舍：即时可见换资源成本。</p><p>生产实现 Refresh 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_9-alias" tabindex="-1">9. Alias <a class="header-anchor" href="#_9-alias" aria-label="Permalink to &quot;9. Alias&quot;">​</a></h2><p>机制：逻辑名原子切索引版本。</p><p>实际使用：零停机重建切换。</p><p>主要失败：未对账就切换。</p><p>验证方法：检查count/hash/version lag。</p><p>取舍：双索引占空间。</p><p>生产实现 Alias 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_10-snapshot-stream" tabindex="-1">10. Snapshot+stream <a class="header-anchor" href="#_10-snapshot-stream" aria-label="Permalink to &quot;10. Snapshot+stream&quot;">​</a></h2><p>机制：固定快照后接水位增量。</p><p>实际使用：全量重建不漏更新。</p><p>主要失败：用墙钟拼接产生缺口。</p><p>验证方法：记录CDC位置并演练。</p><p>取舍：实现复杂但可恢复。</p><p>生产实现 Snapshot+stream 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_11-reconciliation" tabindex="-1">11. Reconciliation <a class="header-anchor" href="#_11-reconciliation" aria-label="Permalink to &quot;11. Reconciliation&quot;">​</a></h2><p>机制：周期比较事实与投影。</p><p>实际使用：发现静默漏失。</p><p>主要失败：只比总count。</p><p>验证方法：按tenant/version/hash抽样。</p><p>取舍：增加读成本但提供可信度。</p><p>生产实现 Reconciliation 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要收益</th><th>关键边界</th></tr></thead><tbody><tr><td>应用双写</td><td>低复杂</td><td>存在漏写窗口</td></tr><tr><td>Outbox</td><td>领域语义清楚</td><td>至少一次重复</td></tr><tr><td>CDC</td><td>覆盖所有写</td><td>物理schema耦合</td></tr><tr><td>全量重建</td><td>修复彻底</td><td>资源与切换成本</td></tr><tr><td>增量修补</td><td>影响小</td><td>可能漏未知损坏</td></tr></tbody></table><h2 id="_13-完整案例-订单实时同步" tabindex="-1">13. 完整案例：订单实时同步 <a class="header-anchor" href="#_13-完整案例-订单实时同步" aria-label="Permalink to &quot;13. 完整案例：订单实时同步&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>PostgreSQL订单、Kafka、OpenSearch；30秒freshness；重复乱序；删除不能复活。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>事务写订单version和outbox。</li><li>以order_id为key发布，consumer批量upsert。</li><li>索引脚本只接受更高source_version。</li><li>delete写version tombstone或维护删除水位。</li><li>逐项解析bulk响应，暂时重试、确定错误DLQ。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>索引最终为数据库最高版本，删除稳定。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>乱序100版本最终最高；commit后崩溃不漏；bulk部分失败可恢复。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>HTTP bulk 200中单项429被忽略导致静默缺文档；必须逐项检查并保留event ID。</p><h3 id="完成判断" tabindex="-1">完成判断 <a class="header-anchor" href="#完成判断" aria-label="Permalink to &quot;完成判断&quot;">​</a></h3><p>订单同步只有在提交后崩溃仍能由 outbox/CDC 补发、100 次乱序最终保留最高版本、删除事件不会被旧更新复活，并逐项处理 bulk 的 429 与 mapping 错误后才算完成。</p><h2 id="_14-完整案例-全量重建v4" tabindex="-1">14. 完整案例：全量重建v4 <a class="header-anchor" href="#_14-完整案例-全量重建v4" aria-label="Permalink to &quot;14. 完整案例：全量重建v4&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>v3 mapping错误，2亿文档，在线写持续；可用额外磁盘1.5倍。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>创建v4 mapping和设置，记录CDC水位P。</li><li>按数据库稳定keyset快照批量写v4。</li><li>应用P后的事件并追到近实时。</li><li>按tenant count/version/hash与查询golden对账。</li><li>短时双读canary后原子切alias，v3保留回退窗口。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>在线切换且更新不丢，旧索引可回退。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>切换前lag为零/阈值内；随机文档版本一致；磁盘watermark安全。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>全量开始后只消费‘现在’事件会在快照边界重复/漏；必须使用一致快照与明确change position。</p><h3 id="完成判断-1" tabindex="-1">完成判断 <a class="header-anchor" href="#完成判断-1" aria-label="Permalink to &quot;完成判断&quot;">​</a></h3><p>v4 重建的验收门槛是快照行数和最高版本对账、CDC 从记录水位连续追平、golden query 与租户抽样 hash 通过、磁盘仍低于停止水位，且 alias 切换后能在回退窗口恢复 v3。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入点</th><th>应观察的系统行为</th><th>不允许的结果</th></tr></thead><tbody><tr><td>输入中加入未知字段/极端长度</td><td>cdc_lag 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>暂停一个处理节点</td><td>outbox_oldest_age 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>让下游返回429或503</td><td>bulk_item_errors 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>制造重复与乱序版本</td><td>version_reject_old 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>使磁盘达到高水位</td><td>tombstone_count 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>让请求在提交后断线</td><td>refresh_time 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>撤销一个租户权限</td><td>segment_merge 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>使后台任务积压超过SLO</td><td>reindex_docs_per_sec 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr></tbody></table><h2 id="_16-调试路径与观测信号" tabindex="-1">16. 调试路径与观测信号 <a class="header-anchor" href="#_16-调试路径与观测信号" aria-label="Permalink to &quot;16. 调试路径与观测信号&quot;">​</a></h2><ol><li><code>cdc_lag</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>outbox_oldest_age</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>bulk_item_errors</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>version_reject_old</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>tombstone_count</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>refresh_time</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>segment_merge</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>reindex_docs_per_sec</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>alias_canary_diff</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>reconciliation_mismatch</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li></ol><p>缺文档时以数据库主键为起点，依次查提交版本、outbox/CDC event、consumer offset、bulk item response 和索引中的 external version；幽灵文档则反向检查 tombstone 是否到达以及是否被更旧更新覆盖。HTTP 200 不能代替逐 item 结果。</p><h2 id="_17-性能、安全与运维边界" tabindex="-1">17. 性能、安全与运维边界 <a class="header-anchor" href="#_17-性能、安全与运维边界" aria-label="Permalink to &quot;17. 性能、安全与运维边界&quot;">​</a></h2><ol><li>所有用户输入有长度、结构、复杂度和超时上限；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>租户与权限条件来自认证主体，不信任请求正文；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>重试有总预算、退避、抖动和幂等保护；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>派生数据能从事实源按明确水位重建；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>敏感正文不进入普通日志、指标标签或公开快照；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>容量按峰值写入、查询、恢复和副本同时估算；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>发布采用版本化结构、canary、对账和回退窗口；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>删除覆盖索引、缓存、快照与下游派生系统；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>依赖不可用时核心正确性不由降级路径破坏；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li><li>运行手册包含暂停、恢复、验证和人工升级条件；对 搜索索引的数据库同步、更新、删除与重建 的实现要给出责任人和可执行验证。</li></ol><h2 id="_18-综合练习与验收" tabindex="-1">18. 综合练习与验收 <a class="header-anchor" href="#_18-综合练习与验收" aria-label="Permalink to &quot;18. 综合练习与验收&quot;">​</a></h2><p>为“订单实时同步”实现最小生产链路，并把“全量重建v4”作为不同约束下的对照。提交配置、请求/响应、数据样例、故障脚本和观测面板。</p><ul><li>[ ] 验收 1：Dual write 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 2：Outbox 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 3：CDC 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 4：External version 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 5：Tombstone 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 6：Bulk API 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 7：Refresh 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 8：Alias 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 提交后崩溃、事件重复、乱序、bulk 部分失败和 tombstone 迟到均有可重复 fixture。</li><li>[ ] 全量快照与增量流用明确 change position 衔接，重建期间新增、更新和删除都不丢失。</li><li>[ ] Alias 切换前保存 count/version/hash 与查询 golden 结果，达到磁盘停止阈值时能够安全中止。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://debezium.io/documentation/reference/stable/connectors/postgresql.html" target="_blank" rel="noreferrer">Debezium PostgreSQL connector</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/api-reference/document-apis/bulk/" target="_blank" rel="noreferrer">OpenSearch Bulk API</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/im-plugin/index-alias/" target="_blank" rel="noreferrer">OpenSearch Index aliases</a>（访问日期：2026-07-17）</li><li><a href="https://www.elastic.co/docs/reference/elasticsearch/rest-apis/reindex-indices" target="_blank" rel="noreferrer">Elasticsearch Reindex API</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/logicaldecoding.html" target="_blank" rel="noreferrer">PostgreSQL 18 logical decoding</a>（访问日期：2026-07-17）</li></ul>`,115)])])}const b=a(l,[["render",o]]);export{u as __pageData,b as default};
